import{_ as e,o as r,c as o,ag as n}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Training & Development","description":"","frontmatter":{},"headers":[],"relativePath":"modules/training.md","filePath":"modules/training.md"}'),a={name:"modules/training.md"};function s(i,t,l,d,g,c){return r(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="training-development" tabindex="-1">Training &amp; Development <a class="header-anchor" href="#training-development" aria-label="Permalink to &quot;Training &amp; Development&quot;">​</a></h1><p>The Training module manages the complete learning and development lifecycle: creating courses, scheduling sessions, enrolling employees, tracking completion, and measuring training effectiveness. It integrates with the Reports module to provide completion rate analytics.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Training</strong> or <code>/training</code>. The module is structured as follows:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Courses</strong></td><td><code>/training/courses</code></td><td>Course catalogue</td></tr><tr><td><strong>Sessions</strong></td><td><code>/training/sessions</code></td><td>Scheduled training events</td></tr><tr><td><strong>Enrollments</strong></td><td><code>/training/enrollments</code></td><td>Employee enrollment and completion tracking</td></tr><tr><td><strong>Reports</strong></td><td><code>/training/reports</code></td><td>Completion rates and analytics</td></tr></tbody></table><hr><h2 id="training-courses" tabindex="-1">Training Courses <a class="header-anchor" href="#training-courses" aria-label="Permalink to &quot;Training Courses&quot;">​</a></h2><p>A course is the base unit — the subject or programme being taught. Sessions are the specific scheduled occurrences of that course.</p><h3 id="creating-a-course" tabindex="-1">Creating a Course <a class="header-anchor" href="#creating-a-course" aria-label="Permalink to &quot;Creating a Course&quot;">​</a></h3><ol><li>Navigate to <strong>Training → Courses</strong></li><li>Click <strong>Add Course</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Course Title</strong></td><td>Yes</td><td>Name of the course (e.g., <code>Leadership Essentials</code>)</td></tr><tr><td><strong>Category</strong></td><td>Yes</td><td>Course category (Technical / Soft Skills / Compliance / Leadership / Onboarding / Safety)</td></tr><tr><td><strong>Delivery Mode</strong></td><td>Yes</td><td>In-person / Online / Hybrid / Self-paced</td></tr><tr><td><strong>Duration</strong></td><td>No</td><td>Total hours (e.g., <code>8 hours</code>)</td></tr><tr><td><strong>Cost per Participant</strong></td><td>No</td><td>Training cost for budgeting</td></tr><tr><td><strong>Provider</strong></td><td>No</td><td>Internal (company-run) or external (third-party vendor)</td></tr><tr><td><strong>Provider Name</strong></td><td>Conditional</td><td>Required if external; name of the training vendor</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Course overview and learning objectives</td></tr><tr><td><strong>Prerequisites</strong></td><td>No</td><td>Other courses that must be completed first</td></tr><tr><td><strong>Pass Score</strong></td><td>No</td><td>Minimum score percentage to mark as completed (e.g., <code>70</code>)</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="course-categories" tabindex="-1">Course Categories <a class="header-anchor" href="#course-categories" aria-label="Permalink to &quot;Course Categories&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Typical Courses</th></tr></thead><tbody><tr><td><strong>Technical</strong></td><td>Programming, tools, software-specific training</td></tr><tr><td><strong>Soft Skills</strong></td><td>Communication, presentation, conflict resolution</td></tr><tr><td><strong>Compliance</strong></td><td>GDPR, health &amp; safety, code of conduct</td></tr><tr><td><strong>Leadership</strong></td><td>Management fundamentals, coaching, strategy</td></tr><tr><td><strong>Onboarding</strong></td><td>New employee orientation and company policies</td></tr><tr><td><strong>Safety</strong></td><td>Fire safety, first aid, workplace hazard training</td></tr></tbody></table><hr><h2 id="training-sessions" tabindex="-1">Training Sessions <a class="header-anchor" href="#training-sessions" aria-label="Permalink to &quot;Training Sessions&quot;">​</a></h2><p>A session is a specific scheduled instance of a course, with defined dates, location, and participant limits.</p><h3 id="creating-a-session" tabindex="-1">Creating a Session <a class="header-anchor" href="#creating-a-session" aria-label="Permalink to &quot;Creating a Session&quot;">​</a></h3><ol><li>Navigate to <strong>Training → Sessions</strong></li><li>Click <strong>Add Session</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Course</strong></td><td>Yes</td><td>Which course this session belongs to</td></tr><tr><td><strong>Session Name</strong></td><td>No</td><td>A distinguishing name if running multiple sessions of the same course</td></tr><tr><td><strong>Start Date</strong></td><td>Yes</td><td>Session start date and time</td></tr><tr><td><strong>End Date</strong></td><td>Yes</td><td>Session end date and time</td></tr><tr><td><strong>Location</strong></td><td>No</td><td>Room name, building, or URL for virtual sessions</td></tr><tr><td><strong>Facilitator</strong></td><td>No</td><td>The trainer (internal employee or external name)</td></tr><tr><td><strong>Max Participants</strong></td><td>No</td><td>Enrollment cap (leave blank for unlimited)</td></tr><tr><td><strong>Status</strong></td><td>Auto</td><td>Scheduled → In Progress → Completed / Cancelled</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="session-status-flow" tabindex="-1">Session Status Flow <a class="header-anchor" href="#session-status-flow" aria-label="Permalink to &quot;Session Status Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Scheduled → In Progress → Completed</span></span>
<span class="line"><span>                        → Cancelled</span></span></code></pre></div><ul><li>Sessions move to <strong>In Progress</strong> automatically when the start date passes</li><li>HR marks them as <strong>Completed</strong> after the session ends</li><li>Mark as <strong>Cancelled</strong> if the session is called off</li></ul><hr><h2 id="enrollment" tabindex="-1">Enrollment <a class="header-anchor" href="#enrollment" aria-label="Permalink to &quot;Enrollment&quot;">​</a></h2><h3 id="enrolling-an-employee" tabindex="-1">Enrolling an Employee <a class="header-anchor" href="#enrolling-an-employee" aria-label="Permalink to &quot;Enrolling an Employee&quot;">​</a></h3><p>HR staff enroll employees in specific sessions:</p><ol><li>Navigate to <strong>Training → Enrollments</strong></li><li>Click <strong>Enroll Employee</strong></li><li>Select the <strong>Session</strong></li><li>Select the <strong>Employee</strong> (or multiple employees)</li><li>Set enrollment status to <strong>Enrolled</strong></li><li>Click <strong>Save</strong></li></ol><p>The employee receives an email notification with session details.</p><h3 id="employee-self-enrollment" tabindex="-1">Employee Self-Enrollment <a class="header-anchor" href="#employee-self-enrollment" aria-label="Permalink to &quot;Employee Self-Enrollment&quot;">​</a></h3><p>Employees can browse available sessions and self-enroll:</p><ol><li>Employee navigates to <strong>My Training → Browse Sessions</strong></li><li>Finds an open session with available spots</li><li>Clicks <strong>Enroll</strong></li><li>Enrollment is created with status <strong>Enrolled</strong> (or <strong>Pending Approval</strong> if HR approval is required)</li></ol><div class="tip custom-block"><p class="custom-block-title">Enrollment Approval</p><p>To require HR approval for self-enrollments, go to <strong>Settings → Training → Require Enrollment Approval</strong> and enable it. Self-enrollments will then have a <strong>Pending Approval</strong> status until HR reviews them.</p></div><h3 id="enrollment-statuses" tabindex="-1">Enrollment Statuses <a class="header-anchor" href="#enrollment-statuses" aria-label="Permalink to &quot;Enrollment Statuses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enrolled</strong></td><td>Confirmed enrollment</td></tr><tr><td><strong>Pending Approval</strong></td><td>Awaiting HR confirmation</td></tr><tr><td><strong>Completed</strong></td><td>Employee attended and completed the session</td></tr><tr><td><strong>Failed</strong></td><td>Attended but did not achieve the pass score</td></tr><tr><td><strong>Absent</strong></td><td>Enrolled but did not attend</td></tr><tr><td><strong>Cancelled</strong></td><td>Enrollment was withdrawn</td></tr></tbody></table><hr><h2 id="marking-completion" tabindex="-1">Marking Completion <a class="header-anchor" href="#marking-completion" aria-label="Permalink to &quot;Marking Completion&quot;">​</a></h2><p>After a session ends, HR marks each enrolled employee&#39;s outcome:</p><ol><li>Navigate to <strong>Training → Sessions</strong></li><li>Click the completed session</li><li>Click <strong>Mark Attendance / Completion</strong></li><li>For each enrolled employee, select: <ul><li><strong>Completed</strong> — attended and passed</li><li><strong>Failed</strong> — attended but did not meet pass score</li><li><strong>Absent</strong> — did not attend</li></ul></li><li>Enter a <strong>Score</strong> (percentage) if the session included an assessment</li><li>Add <strong>Feedback</strong> (optional — visible to the employee)</li><li>Click <strong>Save Outcomes</strong></li></ol><hr><h2 id="scores-and-feedback" tabindex="-1">Scores and Feedback <a class="header-anchor" href="#scores-and-feedback" aria-label="Permalink to &quot;Scores and Feedback&quot;">​</a></h2><p>Each completed enrollment can have:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Score</strong></td><td>Numeric score as a percentage (0–100)</td></tr><tr><td><strong>Pass/Fail</strong></td><td>Calculated based on the course&#39;s Pass Score threshold</td></tr><tr><td><strong>Feedback</strong></td><td>Trainer&#39;s qualitative comments</td></tr><tr><td><strong>Certificate</strong></td><td>Upload a completion certificate (PDF)</td></tr></tbody></table><p>Employees can see their own scores and feedback in <strong>My Training → My History</strong>.</p><hr><h2 id="training-reports" tabindex="-1">Training Reports <a class="header-anchor" href="#training-reports" aria-label="Permalink to &quot;Training Reports&quot;">​</a></h2><p>Navigate to <strong>Reports → Training</strong> or <strong>Training → Reports</strong> for analytics:</p><h3 id="completion-rate-by-category" tabindex="-1">Completion Rate by Category <a class="header-anchor" href="#completion-rate-by-category" aria-label="Permalink to &quot;Completion Rate by Category&quot;">​</a></h3><p>Bar chart showing:</p><ul><li>Total enrollments</li><li>Completed count</li><li>Completion % for each category</li></ul><h3 id="monthly-training-activity" tabindex="-1">Monthly Training Activity <a class="header-anchor" href="#monthly-training-activity" aria-label="Permalink to &quot;Monthly Training Activity&quot;">​</a></h3><p>Line chart of enrollments and completions over the past 12 months.</p><h3 id="department-training-coverage" tabindex="-1">Department Training Coverage <a class="header-anchor" href="#department-training-coverage" aria-label="Permalink to &quot;Department Training Coverage&quot;">​</a></h3><p>Table showing how many employees per department have completed at least one course in the current year.</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Department</td><td>Department name</td></tr><tr><td>Total Employees</td><td>Headcount</td></tr><tr><td>Trained Count</td><td>Employees with at least one completion</td></tr><tr><td>Coverage %</td><td>Trained / Total × 100</td></tr></tbody></table><h3 id="top-courses" tabindex="-1">Top Courses <a class="header-anchor" href="#top-courses" aria-label="Permalink to &quot;Top Courses&quot;">​</a></h3><p>Ranked list of courses by:</p><ul><li>Total enrollments</li><li>Completion rate</li><li>Average score</li></ul><h3 id="individual-training-history" tabindex="-1">Individual Training History <a class="header-anchor" href="#individual-training-history" aria-label="Permalink to &quot;Individual Training History&quot;">​</a></h3><p>Per-employee report showing all courses attended, completion status, scores, and dates. Accessible from the employee profile under the <strong>Training</strong> tab.</p>`,62)])])}const m=e(a,[["render",s]]);export{p as __pageData,m as default};
